package com.example.demo.ui;
import com.example.demo.dto.*;import com.example.demo.models.PermisoUsuario;import com.example.demo.services.*;import com.vaadin.flow.component.button.*;import com.vaadin.flow.component.checkbox.*;import com.vaadin.flow.component.combobox.ComboBox;import com.vaadin.flow.component.datepicker.DatePicker;import com.vaadin.flow.component.dialog.Dialog;import com.vaadin.flow.component.grid.Grid;import com.vaadin.flow.component.orderedlayout.*;import com.vaadin.flow.component.textfield.*;import com.vaadin.flow.router.*;import java.util.*;import java.util.function.Function;import java.util.stream.Collectors;
@Route(value="usuarios",layout=MainLayout.class) @PageTitle("Usuarios | Franco") public class UsuariosView extends VerticalLayout{
private final UsuarioService usuarios;private final EmpleadoService empleados;private final Grid<UsuarioDTO>grid=new Grid<>(UsuarioDTO.class,false);private Map<Long,EmpleadoDTO>fichas=Map.of();
public UsuariosView(UsuarioService usuarios,EmpleadoService empleados){this.usuarios=usuarios;this.empleados=empleados;addClassName("content-view");setSizeFull();Button add=new Button("Nuevo usuario",e->form(null));add.addThemeVariants(ButtonVariant.LUMO_PRIMARY);grid.addColumn(u->u.nombre()+" "+u.apellido()).setHeader("Nombre");grid.addColumn(UsuarioDTO::email).setHeader("Email");grid.addColumn(u->label(u.rol())).setHeader("Perfil");grid.addColumn(u->value(fichas.get(u.id()),EmpleadoDTO::puesto)).setHeader("Puesto");grid.addColumn(u->value(fichas.get(u.id()),EmpleadoDTO::legajo)).setHeader("Legajo");grid.addColumn(u->u.activo()?"Activo":"Inactivo").setHeader("Estado");grid.addComponentColumn(u->new Button("Editar",e->form(u))).setHeader("Acciones");add(ViewSupport.header("Usuarios",add),grid);expand(grid);refresh();}
private void refresh(){fichas=empleados.listar().stream().collect(Collectors.toMap(EmpleadoDTO::usuarioId,Function.identity()));grid.setItems(usuarios.listar());}
private void form(UsuarioDTO u){EmpleadoDTO employee=u==null?null:fichas.get(u.id());Dialog d=new Dialog();d.setHeaderTitle(u==null?"Nuevo usuario":"Editar usuario");d.setWidth("min(820px,95vw)");TextField name=new TextField("Nombre"),surname=new TextField("Apellido"),email=new TextField("Email");IntegerField dni=new IntegerField("DNI");PasswordField pass=new PasswordField(u==null?"Contraseña":"Nueva contraseña (opcional)");ComboBox<String>role=new ComboBox<>("Perfil");role.setItems("USUARIO","ADMIN","SUPER_ADMIN");role.setItemLabelGenerator(this::label);role.setValue("USUARIO");Checkbox active=new Checkbox("Activo",true);TextField file=new TextField("Legajo"),position=new TextField("Puesto"),emergency=new TextField("Teléfono de emergencia");DatePicker hired=new DatePicker("Fecha de contratación");BigDecimalField salary=new BigDecimalField("Sueldo de referencia");TextArea notes=new TextArea("Observaciones");CheckboxGroup<String>permissions=new CheckboxGroup<>("Permisos adicionales para cajeros");permissions.setItems(Arrays.stream(PermisoUsuario.Permiso.values()).map(Enum::name).toList());permissions.setItemLabelGenerator(this::permissionLabel);if(u!=null){name.setValue(u.nombre());surname.setValue(u.apellido());dni.setValue(u.dni());email.setValue(u.email());role.setValue(u.rol());active.setValue(u.activo());}if(employee!=null){set(file,employee.legajo());set(position,employee.puesto());hired.setValue(employee.fechaContratacion());salary.setValue(employee.sueldo());set(emergency,employee.telefonoEmergencia());notes.setValue(employee.observaciones()==null?"":employee.observaciones());permissions.select(employee.permisos());}d.add(new VerticalLayout(new HorizontalLayout(name,surname,dni),email,pass,new HorizontalLayout(role,active),new HorizontalLayout(file,position),new HorizontalLayout(hired,salary),emergency,notes,permissions));Button save=new Button("Guardar",e->{try{usuarios.guardarCompleto(u==null?null:u.id(),new UsuarioDTO(u==null?null:u.id(),name.getValue(),surname.getValue(),dni.getValue(),email.getValue(),role.getValue(),active.getValue()),pass.getValue(),new EmpleadoDTO(u==null?null:u.id(),name.getValue(),surname.getValue(),email.getValue(),role.getValue(),active.getValue(),file.getValue(),position.getValue(),hired.getValue(),salary.getValue(),emergency.getValue(),notes.getValue(),permissions.getSelectedItems()),UserSession.getUser().id());d.close();refresh();ViewSupport.success("Usuario guardado");}catch(RuntimeException ex){ViewSupport.error(ex);}});save.addThemeVariants(ButtonVariant.LUMO_PRIMARY);d.getFooter().add(new Button("Cancelar",e->d.close()),save);d.open();}
private String label(String role){return switch(role){case"USUARIO"->"Cajero";case"ADMIN"->"Encargado";default->"Dueño";};}private String permissionLabel(String permission){return switch(permission){case"MODIFICAR_PRECIOS"->"Modificar precios";case"APLICAR_DESCUENTOS"->"Aplicar descuentos";case"ANULAR_VENTAS"->"Anular ventas";case"REALIZAR_DEVOLUCIONES"->"Realizar devoluciones";case"AJUSTAR_STOCK"->"Ajustar stock";case"REGISTRAR_COMPRAS"->"Registrar compras";case"VER_REPORTES"->"Ver reportes";case"ADMINISTRAR_CLIENTES"->"Administrar clientes";case"COBRAR_CUENTAS"->"Cobrar cuentas corrientes";default->permission;};}private String value(EmpleadoDTO e,Function<EmpleadoDTO,String>accessor){if(e==null)return"-";String v=accessor.apply(e);return v==null||v.isBlank()?"-":v;}private void set(TextField f,String v){f.setValue(v==null?"":v);}}
